cd /home/ctfplayer/work && python3 - << 'PY'
import json, tarfile, os, shutil, base64
root='.'
with open('manifest.json') as f: mani=json.load(f)[0]
layers=mani['Layers']
print('Manifest layer order:')
for i,l in enumerate(layers,1): print(i,l)

# prepare dirs
shutil.rmtree('extracted_layers',ignore_errors=True)
shutil.rmtree('merged_fs_states',ignore_errors=True)
os.makedirs('extracted_layers',exist_ok=True)
os.makedirs('merged_fs_states',exist_ok=True)
merged='merged_current'
shutil.rmtree(merged,ignore_errors=True)
os.makedirs(merged,exist_ok=True)

relevant=['p-flag.txt','flag.txt','tmp.txt']

def print_hits(stage,path):
    for r in relevant:
        p=os.path.join(path,r)
        if os.path.exists(p):
            try:
                data=open(p,'rb').read()
                print(f'[{stage}] {r} exists, size={len(data)} content={data!r}')
            except Exception as e:
                print(f'[{stage}] {r} exists but read err {e}')

for idx,layer_rel in enumerate(layers,1):
    layer_dir=os.path.dirname(layer_rel)
    layer_tar=layer_rel
    print('\n==== Layer',idx,layer_dir,'====')
    with tarfile.open(layer_tar,'r') as tf:
        names=tf.getnames()
        print('tar -tf entries:')
        for n in names: print(' ',n)
        # extract separate
        outdir=os.path.join('extracted_layers',f'{idx:02d}_{layer_dir}')
        os.makedirs(outdir,exist_ok=True)
        tf.extractall(outdir)

    # apply to merged with whiteouts handling by scanning extracted layer
    outdir=os.path.join('extracted_layers',f'{idx:02d}_{layer_dir}')
    # walk extracted files sorted for deterministic
    entries=[]
    for dp, dns, fns in os.walk(outdir):
        rel_dp=os.path.relpath(dp,outdir)
        if rel_dp=='.': rel_dp=''
        for d in dns:
            entries.append((os.path.join(rel_dp,d),True))
        for f in fns:
            entries.append((os.path.join(rel_dp,f),False))
    # process whiteout files first
    for rel,isdir in sorted(entries):
        base=os.path.basename(rel)
        parent=os.path.dirname(rel)
        if not isdir and base.startswith('.wh.'):
            target=base[4:]
            if target=='.wh..opq':
                # remove all in parent dir in merged
                mparent=os.path.join(merged,parent)
                if os.path.isdir(mparent):
                    for item in os.listdir(mparent):
                        p=os.path.join(mparent,item)
                        if os.path.isdir(p) and not os.path.islink(p): shutil.rmtree(p)
                        else: os.remove(p)
                    print(' applied opq whiteout on',parent or '.')
            else:
                victim=os.path.join(merged,parent,target)
                if os.path.exists(victim) or os.path.islink(victim):
                    if os.path.isdir(victim) and not os.path.islink(victim): shutil.rmtree(victim)
                    else: os.remove(victim)
                    print(' whiteout removed',os.path.join(parent,target))
    # then copy non-whiteout
    for rel,isdir in sorted(entries):
        base=os.path.basename(rel)
        if (not isdir) and base.startswith('.wh.'): continue
        src=os.path.join(outdir,rel)
        dst=os.path.join(merged,rel)
        if isdir:
            os.makedirs(dst,exist_ok=True)
        else:
            os.makedirs(os.path.dirname(dst),exist_ok=True)
            if os.path.islink(src):
                if os.path.lexists(dst): os.remove(dst)
                os.symlink(os.readlink(src),dst)
            else:
                shutil.copy2(src,dst)

    # save snapshot
    snap=os.path.join('merged_fs_states',f'{idx:02d}_{layer_dir}')
    shutil.rmtree(snap,ignore_errors=True)
    shutil.copytree(merged,snap,symlinks=True)

    # locate relevant files in this layer extracted and merged snapshot
    for r in relevant:
        p=os.path.join(outdir,r)
        if os.path.exists(p):
            print(f'layer artifact {r}:',open(p,'rb').read())
    print_hits(f'merged after layer {idx}',merged)

print('\nBase64 decode:')
s='ZmxhZ3tuM3Yzcl9sMzR2M181M241MTcxdjNfMW5mMHJtNDcxMG5fdW5wcjA='
print(base64.b64decode(s).decode())

print('\nFinal merged relevant files:')
print_hits('final',merged)
